mapper.select:
select
,
c.name AS customerName
from pet p
left join customer c on p.customer_id = c.id


        and p.nickname like concat('%', #{nickname}, '%')


        and p.breed = #{breed}


        and p.vaccine_status = #{vaccineStatus}


        and p.customer_id = #{customerId}


order by p.update_time desc

select

from pet p
where p.id = #{id}
